"use client";

import { useEffect, useState } from "react";

export default function Splash() {
  const [hide, setHide] = useState(false);
  const [progress, setProgress] = useState(1);

  useEffect(() => {
    const interval = setInterval(() => {
      setProgress((p) => Math.min(100, p + 3));
    }, 60);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    const t = setTimeout(() => {
      setHide(true);
      window.dispatchEvent(new CustomEvent("yeble:splash-hidden"));
    }, 2600);
    return () => clearTimeout(t);
  }, []);

  if (hide) return null;

  return (
    <div className="fixed inset-0 z-40 flex items-center justify-center overflow-hidden bg-[#fffef0]">
      <div className="absolute inset-0 animate-sway bg-[radial-gradient(circle_at_30%_30%,#2cff9188,transparent_30%),radial-gradient(circle_at_75%_20%,#dffb5f55,transparent_32%),radial-gradient(circle_at_65%_80%,#24c86c55,transparent_28%)] blur-3xl opacity-80" />
      <div className="absolute inset-0 bg-[linear-gradient(150deg,#fffef0,#f7f3dc_45%,#fffef0)] opacity-85" />
      <div className="absolute inset-[-20%] bg-grid" />
      <div className="relative w-[520px] max-w-[92vw] rounded-[32px] border border-[#e3decf] bg-white/80 px-10 py-12 shadow-[0_25px_120px_rgba(90,255,130,0.35)] backdrop-blur-2xl">
        <div className="flex flex-col items-center gap-3 text-center">
          <img src="/logo.svg" alt="Yeble.careers" className="h-16 w-auto" />
          <span className="text-sm uppercase tracking-[0.32em] text-[#2d6a3e]">Accelerate your Placement</span>
        </div>
        <div className="mt-8 h-4 w-full overflow-hidden rounded-full bg-[#f4f2e3] shadow-inner">
          <div
            className="h-full rounded-full bg-gradient-to-r from-[#27c06b] via-[#dff95b] to-[#1fb35f] transition-all duration-100"
            style={{ width: `${progress}%` }}
          />
        </div>
        <div className="mt-4 flex items-center justify-center gap-3 text-[#123622]">
          <div className="h-6 w-6 animate-spin rounded-full border-2 border-[#27c06b] border-t-transparent" />
          <p className="text-base font-semibold">{progress}%</p>
        </div>
      </div>
    </div>
  );
}
